/**
 * Integration Test Setup
 *
 * Global setup file for integration tests.
 * Initializes test environment, database connections,
 * and provides utilities for test isolation.
 *
 * @module tests/integration/setup
 */

import 'reflect-metadata';
import { beforeAll, afterAll, beforeEach, vi } from 'vitest';

// Mock environment variables for testing
vi.stubEnv('NODE_ENV', 'test');
vi.stubEnv('PORT', '3001');
vi.stubEnv('APP_NAME', 'E-Menum Test');
vi.stubEnv('APP_DOMAIN', 'test.e-menum.net');
vi.stubEnv('APP_URL', 'http://localhost:3001');
vi.stubEnv('CORS_ORIGIN', '*');
vi.stubEnv('JWT_SECRET', 'test-jwt-secret-key-that-is-at-least-32-chars-long');
vi.stubEnv('JWT_REFRESH_SECRET', 'test-jwt-refresh-secret-key-at-least-32-chars');
vi.stubEnv('JWT_ACCESS_EXPIRY', '15m');
vi.stubEnv('JWT_REFRESH_EXPIRY', '7d');
vi.stubEnv('DATABASE_URL', 'postgresql://test:test@localhost:5432/emenum_test');
vi.stubEnv('REDIS_URL', 'redis://localhost:6379/1');
vi.stubEnv('LOG_LEVEL', 'error');
vi.stubEnv('UPLOAD_DIR', './uploads');
vi.stubEnv('MAX_UPLOAD_SIZE', '10485760');

// Global test lifecycle hooks
beforeAll(async () => {
  // Setup logging suppression in tests
  vi.spyOn(console, 'log').mockImplementation(() => {});
  vi.spyOn(console, 'info').mockImplementation(() => {});
});

afterAll(async () => {
  // Restore console
  vi.restoreAllMocks();
});

beforeEach(() => {
  // Clear all mocks before each test
  vi.clearAllMocks();
});
